export class Storage {
  constructor() {
    this.data = new Map();
  }

  async get(id) {
    if (!this.data.has(id)) {
      throw new Error('Not found: ' + id);
    }
    return this.data.get(id);
  }

  async set(item) {
    this.data.set(item.id, item);
  }

  async query(filter) {
    const results = [];
    for (const item of this.data.values()) {
      let matches = true;
      for (const [key, value] of Object.entries(filter)) {
        if (item[key] !== value) {
          matches = false;
          break;
        }
      }
      if (matches) results.push(item);
    }
    return results;
  }
}

export async function loadKernel(require) {
  const { Storage } = await require('kernel-storage');

  class Kernel {
    constructor() {
      this.storage = new Storage();
      this.rootElement = document.createElement('div');
      this.rootElement.innerHTML = `
        <div style="padding: 40px; max-width: 600px; margin: 0 auto;">
          <h1>Hobson is running!</h1>
          <p>Kernel loaded successfully from items.</p>
          <p style="color: #666;">This is a minimal bootstrap architecture demonstration.</p>
          <hr style="margin: 20px 0;">
          <h3>Try this in the console:</h3>
          <pre style="background: #f5f5f5; padding: 15px; border-radius: 4px;">// Access the kernel
window.kernel

// Access storage
await window.kernel.storage.set({
  id: 'test-item',
  type: 'test',
  content: { text: 'Hello!' }
});

const item = await window.kernel.storage.get('test-item');
console.log(item);</pre>
        </div>
      `;
    }

    async boot() {
      console.log('Kernel booted successfully');
      console.log('Available: window.kernel');
    }

    reloadKernel() {
      window.postMessage({ type: 'reload-kernel' }, '*');
    }
  }

  return Kernel;
}
